        </div>
        <div className="flex items-center gap-4 opacity-90">
          <svg viewBox="0 0 24 24" width="24" height="24" fill="white"><path d="M18 16.08c-.76 0-1.44.3-1.96.77L8.91 12.7c.05-.23.09-.46.09-.7s-.04-.47-.09-.7l7.05-4.11c.54.5 1.25.81 2.04.81 1.66 0 3-1.34 3-3s-1.34-3-3-3-3 1.34-3 3c0 .24.04.47.09.7L8.04 9.81C7.5 9.31 6.79 9 6 9c-1.66 0-3 1.34-3 3s1.34 3 3 3c.79 0 1.5-.31 2.04-.81l7.12 4.16c-.05.21-.08.43-.08.65 0 1.61 1.31 2.92 2.92 2.92 1.61 0 2.92-1.31 2.92-2.92s-1.31-2.92-2.92-2.92z"></path></svg>
          <button onClick={clearChat} className="p-1"><TrashIcon className="w-5 h-5" /></button>
          <svg viewBox="0 0 24 24" width="24" height="24" fill="white"><path d="M12 8c1.1 0 2-.9 2-2s-.9-2-2-2-2 .9-2 2 .9 2 2 2zm0 2c-1.1 0-2 .9-2 2s.9 2 2 2 2-.9 2-2-.9-2-2-2zm0 6c-1.1 0-2 .9-2 2s.9 2 2 2 2-.9 2-2-.9-2-2-2z"></path></svg>
        </div>
      </header>

      {/* Messages Scroll Area */}
      <main 
        ref={scrollRef}
        className="relative z-10 flex-1 overflow-y-auto px-4 py-4 custom-scrollbar flex flex-col gap-2"
      >
        {messages.map((msg) => (
          <div 
            key={msg.id} 
            className={`flex w-full ${msg.role === MessageRole.USER ? 'justify-end' : 'justify-start'}`}
          >
            <div 
              className={`relative max-w-[85%] px-3 py-1.5 shadow-sm ${
                msg.role === MessageRole.USER 
                  ? 'bg-[#dcf8c6] rounded-l-lg rounded-br-lg rounded-tr-none' 
                  : 'bg-white rounded-r-lg rounded-bl-lg rounded-tl-none'
              }`}
              style={{ minWidth: '80px' }}
            >
              {/* Message Content */}
              {msg.parts.map((part, idx) => (
                <div key={idx} className="flex flex-col gap-1">
                  {part.inlineData && (
                    <div className="rounded-lg overflow-hidden my-1">
                      <img 
                        src={`data:${part.inlineData.mimeType};base64,${part.inlineData.data}`} 
                        alt="Image" 
                        className="max-w-full h-auto rounded-md"
                      />
                    </div>
                  )}
                  {part.text && (
                    <p className="text-[14.5px] leading-relaxed text-[#111b21] whitespace-pre-wrap pr-12">
                      {part.text}
                    </p>
                  )}
                </div>
              ))}

              {/* Timestamp and Checkmarks */}
              <div className="absolute bottom-1 right-2 flex items-center gap-1">
                <span className="text-[10px] text-[#667781]">
                  {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', hour12: true })}
                </span>
                {msg.role === MessageRole.USER && (
                  <DoubleCheck className="w-3.5 h-3.5 text-[#53bdeb]" />
                )}
              </div>
            </div>
          </div>
        ))}
        {isTyping && (
          <div className="flex justify-start">
            <div className="bg-white px-4 py-2 rounded-lg rounded-tl-none shadow-sm flex items-center gap-1">
              <span className="text-xs text-gray-500 italic">Typing...</span>
            </div>
          </div>
        )}
      </main>

      {/* Input Area (WhatsApp Mobile Style) */}
      <footer className="relative z-10 p-2 flex items-end gap-2 bg-transparent">
        <div className="flex-1 flex items-end gap-2 bg-white rounded-full px-3 py-1 shadow-md border border-gray-200/50">
          <button className="p-2 text-gray-500 hover:text-gray-700">
             <svg viewBox="0 0 24 24" width="24" height="24" fill="currentColor"><path d="M12 7c2.76 0 5 2.24 5 5 0 .65-.13 1.26-.36 1.83l2.92 2.92c1.51-1.26 2.44-3.13 2.44-5.25 0-3.76-3.05-6.81-6.81-6.81-.45 0-.89.04-1.32.12l2.13 2.13c.33-.04.66-.06 1-.06zM5.27 4L4 5.27l2.21 2.21C4.7 8.7 3.75 10.46 3.75 12.5c0 3.76 3.05 6.81 6.81 6.81 2.04 0 3.8-.84 5.04-2.2l2.38 2.38L19.23 18.2 5.27 4zm5.29 13.31c-2.65 0-4.81-2.16-4.81-4.81 0-.61.12-1.18.33-1.7l1.37 1.37c-.12.18-.2.4-.2.63 0 .61.5 1.11 1.11 1.11.23 0 .44-.08.62-.2l1.37 1.37c-.52.21-1.09.33-1.7.33z"></path></svg>
          </button>

          <textarea
            value={inputValue}
            onChange={(e) => setInputValue(e.target.value)}
            onKeyDown={(e) => {
              if (e.key === 'Enter' && !e.shiftKey) {
                e.preventDefault();
                handleSend();
              }
            }}
            placeholder="Type a message"
            className="flex-1 bg-transparent border-none focus:ring-0 text-[#111b21] py-2.5 text-[15px] resize-none max-h-32 min-h-[40px] placeholder:text-gray-400"
            rows={1}
            disabled={isTyping}
          />

          <button 
            onClick={() => fileInputRef.current?.click()}
            className="p-2 text-gray-500 rotate-45"
          >
            <PaperclipIcon className="w-5 h-5" />
            <input 
              type="file" 
              ref={fileInputRef} 
              onChange={handleFileChange} 
              className="hidden" 
              accept="image/*"
            />
          </button>
          <button className="p-2 text-gray-500">
             <svg viewBox="0 0 24 24" width="24" height="24" fill="currentColor"><path d="M12 14c1.66 0 3-1.34 3-3V5c0-1.66-1.34-3-3-3S9 3.34 9 5v6c0 1.66 1.34 3 3 3z"></path><path d="M17 11c0 2.76-2.24 5-5 5s-5-2.24-5-5H5c0 3.53 2.61 6.43 6 6.92V21h2v-3.08c3.39-.49 6-3.39 6-6.92h-2z"></path></svg>
          </button>
        </div>

        {/* Floating Green Send Button */}
        <button
          onClick={handleSend}
          disabled={(!inputValue.trim() && !selectedImage) || isTyping}
          className={`flex-shrink-0 w-12 h-12 rounded-full flex items-center justify-center transition-all shadow-md ${
            (!inputValue.trim() && !selectedImage) || isTyping 
              ? 'bg-[#128C7E] opacity-70' 
              : 'bg-[#00a884] text-white hover:scale-105'
          }`}
        >
          <SendIcon className="w-6 h-6 ml-0.5" />
        </button>
      </footer>

      {/* Image Preview Overlay */}
      {selectedImage && (
        <div className="absolute inset-x-0 bottom-20 px-4 z-20">
          <div className="bg-white p-3 rounded-xl shadow-2xl border border-gray-100 flex items-center gap-3 w-fit mx-auto animate-in slide-in-from-bottom-5">
            <img 
              src={`data:${selectedImage.mimeType};base64,${selectedImage.data}`} 
              alt="Preview" 
              className="w-16 h-16 object-cover rounded-lg border border-gray-100" 
            />
            <button 
              onClick={() => setSelectedImage(null)}
              className="bg-gray-100 p-2 rounded-full text-gray-500 hover:text-rose-500"
            >
              <PlusIcon className="w-5 h-5 rotate-45" />
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;
